const letter = $json.letter_text;
const source = $json.source_letter;

const platforms = [
  {
    platform: 'x',
    content_type: 'thread',
    preview_text: 'Thread: ' + letter.slice(0, 120) + '...',
    full_content: '1/ ' + letter.slice(0, 280) + '\n\n2/ Key insight: operational discipline is the edge.\n\n3/ One number: most scanned setups rejected. That is the feature.\n\n4/ What\'s next: escalation routing live this week.\n\n5/ Angel Precision is in controlled beta. Apply for access. 🧵',
    source_letter: source
  },
  {
    platform: 'linkedin',
    content_type: 'post',
    preview_text: letter.slice(0, 150) + '...',
    full_content: 'A quick operator note for anyone following what we\'re building at Angel Precision.\n\n' + letter.slice(0, 600) + '\n\nFull weekly letter: [link]\n\n#AlgoTrading #OperatorMindset #SystemsThinking',
    source_letter: source
  },
  {
    platform: 'substack',
    content_type: 'article',
    preview_text: source,
    full_content: letter,
    source_letter: source
  }
];

return platforms.map(p => ({ json: p }));
